INSERT INTO `a_tn2_mobqna_list` VALUES (35,'mobqna',-35,1,0,NULL,35,0,NULL,1000,1,NULL,NULL,NULL,2,0,'관리자',1,'1.209.175.20',1393655680,1394526264,55,NULL,NULL,NULL,'건의 및 개선 요청 게시판입니다.',0,'관리자','bible','',NULL,NULL,NULL,'E5HMSbsBNi4FY',0,NULL,'안녕하세요.\r\nUBF 성경읽기서비스를 사용하시다가 \r\n오류 수정사항 및 개선의견이 있으시면 본 게시판에 올려주시기바랍니다.',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(36,'mobqna',-36,1,0,NULL,36,0,NULL,1,1,NULL,NULL,NULL,1,0,'martin',0,'74.88.201.81',1393925567,1393941302,71,NULL,NULL,NULL,'아주 좋아요..한가지 문의해도 될까요?',0,'martin','martin2007','martin20071001@gmail.com',NULL,'1',NULL,'ozK79lIASkF56',0,NULL,'혹시 다른 영어 버전도 볼 수 있을까요?. 예를 들면 NLT.  ESV NKJV.  등등이요...',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(38,'mobqna',-38,1,0,NULL,38,0,NULL,1,1,NULL,NULL,NULL,1,0,'이빌립',0,'195.160.253.4',1394125617,1394204190,36,NULL,NULL,NULL,'영어 일용할 양식 추가요청',0,'이빌립','philiplee','philipleeubf@hotmail.com',NULL,'1',NULL,'s4URRz.FGIPYM',0,NULL,'안녕하세요. 좋은 프로그램을 만들어 주셔서 감사합니다.\r\n한가지 요청 드리고 싶은 것은 현재 한글 성경에 일용할 양식을 바로 연결해서 확인할 수 있는 것처럼 \r\n영어성경에도 영어 일용할 양식으로 바로 link해서 확인할 수 있는 기능을 추가해 주시면 아주 편할 것 같습니다. \r\n\r\n감사합니다. ',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(39,'mobqna',-39,1,0,NULL,39,0,NULL,1,1,NULL,NULL,NULL,1,0,'장선준',0,'211.36.141.251',1394147574,1394171487,34,NULL,NULL,NULL,'로긴문제',0,'장선준','mweagle','seonjun.jang@gmail.com',NULL,'1',NULL,'UaNrD4yVSccNE',0,NULL,'양식보려고하는데 자꾸로긴하라는메세지가뜨네요 로긴해도무한반복입니다',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(40,'mobqna',-40,1,0,NULL,40,0,NULL,1,1,NULL,NULL,NULL,1,0,'ehose',0,'61.102.136.130',1394360395,1394500508,42,NULL,NULL,NULL,'성경이름과 몇장표시 고정가능한가요',0,'ehose','ehose','ehose@hanmail.net',NULL,'1',NULL,'QR.cxCsObb4qs',0,NULL,'너무 좋은 프로그렘 감사합니다 \r\n맥채인 및성경을 읽을때 중간에 몇장인지 잊을때가있어 \r\n맨위편에 성경이름과 몇장표시는 고정되어있거나, 아니면\r\n읽는 절수 앞에 성경이름(줄임)과 몇장표시가 되어있으면\r\n잊기잘하는 머리탓하지 않을텐데 \r\n기능할지 모르겠 습니다 ~~\r\n',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(41,'mobqna',-41,1,0,NULL,41,0,NULL,1,1,NULL,NULL,NULL,1,0,'정다윗',0,'175.192.140.61',1394492175,1394526154,22,NULL,NULL,NULL,'일용할양식 웹 서비스',0,'정다윗','k2jung','k2jung3@daum.net',NULL,'1',NULL,'.4H5ZuLarkUck',0,NULL,'생명의 말씀을 보면 웹으로 유료 서비스를 하고 있는 것 같이 스마트폰에 맞추어 출판 보다는 웹으로 가야 되지 않을까?',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(42,'mobqna',-42,1,0,NULL,42,0,NULL,1,1,NULL,NULL,NULL,1,0,'dreamer',0,'119.192.249.58',1394521872,1394525975,20,NULL,NULL,NULL,'구절 검색기능',0,'dreamer','ykim','yawp82@naver.com',NULL,'1',NULL,'w1D95DLySm.ZI',0,NULL,'정말 유익하고 좋은 프로그램을 선물로 받은 것 같아서 감사합니다.\r\n\r\n그런데 성경구절 검색기능도 있으면 좋을 것 같은데, 제가 찾지 못한 것인지요? \r\n\r\n없다면 나중에라도 추가해 주시면 매우 감사하겠습니다.\r\n',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(43,'mobqna',-43,1,0,NULL,43,0,NULL,1,1,NULL,NULL,NULL,1,0,'한나',0,'89.17.114.179',1394532280,1394630128,31,NULL,NULL,NULL,'우선 감사의 말씀드리고요.',0,'한나','joyfulljo','joyfulljo@hanmail.net',NULL,'1',NULL,'w8EberPMUsCIE',0,NULL,'감사합니다. \r\n한가지 여쭈어 볼것은 주일예배메세지를 mp3화일로올려주는 것도 가능하신지요?\r\n성경읽기와는 상관없는것 같지만. 한번 문의드려 봅\r\n니다.  ',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(44,'mobqna',-44,1,0,NULL,44,0,NULL,1,1,NULL,NULL,NULL,2,0,'충성',0,'121.66.159.166',1394842040,1400660091,43,NULL,NULL,NULL,'삼성메가스마트폰에서는 체크버튼이보이는데 제스마트폰에서는체크버튼이안보이네요',0,'충성','bless25','learningmind@naver.com',NULL,'1',NULL,'kHLOLOoZkVWqs',0,NULL,'성경읽기 서비스가 많이 유용하게 만들어져서 감사합니다. \r\n제가 몰라서 그런데 노트북에서는 체크버튼이 보여서 읽은것을 체크 할수 있는데 \r\n스마트 폰에서는 체크 버튼이 아예 안보이고 있습니다.\r\n어떻게 해야 하나요? \r\n제 스마트폰 기종은 LG LU6200 (안드로이드 계열) 입니다. ',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,NULL,NULL,NULL),(45,'mobqna',-45,1,0,NULL,45,0,NULL,5,1,NULL,NULL,NULL,0,0,'브리스가',0,'211.206.241.195',1396708070,0,25,NULL,NULL,NULL,'정말넘좋아요~!',0,'브리스가','trulychung','tr