ULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(112,'mobqna',-112,1,0,NULL,112,0,NULL,1,1,NULL,NULL,NULL,1,0,'장사무엘',0,'183.99.230.214',1485946932,NULL,17,NULL,NULL,NULL,'주석은 안되는건가요?',0,'장사무엘','dnajs','gtoc7@naver.com',NULL,NULL,NULL,'',0,NULL,'예전 초기 버전에서는 성경 구절 옆에 [주]를 누르면 주석이 잘 나왔었는데\r\n요즘 버전에서는 구절을 클릭하면 \'주석\'이라는 메뉴가 뜨긴 하는데, 눌러도 주석이 나오질 않아요~',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(113,'mobqna',-113,1,0,NULL,113,0,NULL,1,1,NULL,NULL,NULL,1,0,'박마가_',0,'220.117.54.240',1486297240,NULL,20,NULL,NULL,NULL,'영어 성경에서 사전 연결시 본문이 자동 Highlight 됩니다.',0,'박마가_','yspark0216','yspark0216@empal.com',NULL,NULL,NULL,'',0,NULL,'Highlight 안되도록 수정 되면 더 좋을 것 같습니다.\r\n수고와 헌신에 감사드립니다!',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(114,'mobqna',-114,1,0,NULL,114,0,NULL,1,1,NULL,NULL,NULL,1,0,'MARY13',0,'117.111.2.126',1488250523,NULL,20,NULL,NULL,NULL,'영어성경 niv',0,'MARY13','MARY13','sdn0613@naver.com',NULL,NULL,NULL,'',0,NULL,'안녕하세요:) 귀한 성경앱 감사합니다. niv 성경도 함께 보면서 잘 사용하고 있는데, 누가복음 5장 10절 말씀이 다른 곳에서 검색한 것과 달라서 문의드립니다^^ 홀리넷에서는 catch men 으로 나왔는데 여기서는 fish로 나와서요ㅎㅎ 버전 차이 같긴한데 확인 부탁드립니다^^',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(115,'mobqna',-115,1,0,NULL,115,0,NULL,1,1,NULL,NULL,NULL,1,0,'태양박',0,'121.186.55.191',1492548726,NULL,10,NULL,NULL,NULL,'글씨 크기조절 가능하면 좋겠어요',0,'태양박','ytp2030','ytp2030@naver.com',NULL,NULL,NULL,'',0,NULL,'양식을 볼때 글씨가 작아서 잘않보여요.\r\n크게하고 싶은데,,,,, \r\n방법 알려주세요',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(116,'mobqna',-116,1,0,NULL,116,0,NULL,1,1,NULL,NULL,NULL,1,0,'StevenLee',0,'118.36.155.171',1496783280,NULL,10,NULL,NULL,NULL,'현재 읽고 있는 장 표시 관련',0,'StevenLee','leewonly','leewonly@nate.com',NULL,NULL,NULL,'',0,NULL,'성경 본문을 따라 스크롤 다운하면 내가 읽고있는 장이 어디인지 몰라서 다시 스크롤 업하는 경우가 있습니다. \r\n화면 상단에 현재 읽고 있는 성경과 장수가 계속 표시되면 좋을 것 같습니다. ',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(117,'mobqna',-117,1,0,NULL,117,0,NULL,1,1,NULL,NULL,NULL,1,0,'불타는감자',0,'122.47.102.4',1500475544,NULL,11,NULL,NULL,NULL,'성경 읽으며 다음 장 넘어갈때 불편사항 ㅡ 눈부심',0,'불타는감자','hygjob','hygjob@naver.com',NULL,NULL,NULL,'',0,NULL,'안녕하세요.\r\n좋은 애플리케이션에 신경써 주셔서 고맙습니다\r\n\r\n현재 검은 바탕테마로 사용중인데요. 성경을 읽으며 다음장으로 넘어갈때\r\n페이지 로딩시에 빈 하얀페이지가 표시되니  눈이 부시네요. (검은색 ->흰색에따른 눈부심)\r\n\r\n페이지 로딩시 테마에 맞추어 검은 바탕이 될수는 없을까요?\r\n\r\n\r\n',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(118,'mobqna',-118,1,0,NULL,118,0,NULL,1,1,NULL,NULL,NULL,1,0,'불타는감자',0,'122.47.102.4',1500475950,NULL,9,NULL,NULL,NULL,'페이지 로딩타임이 긴데요',0,'불타는감자','hygjob','hygjob@naver.com',NULL,NULL,NULL,'',0,NULL,'안녕하세요. \r\n좋은 어플 감사합니다. \r\n\r\n성경을 읽을때 다음 장으로 넘어갈때 \r\n페이지 로딩 타임이 긴데 개선이 되면 좀 더 편하게 볼 수 있을 것 같습니다.',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(119,'mobqna',-119,1,0,NULL,119,0,NULL,1,1,NULL,NULL,NULL,1,0,'임요한',0,'121.131.236.51',1509226914,NULL,9,NULL,NULL,NULL,'시간이 지나면 내용이 사라집니다',0,'임요한','jslim55','jslim55@hanmail.net',NULL,NULL,NULL,'',0,NULL,'양식 내용을 쓰다가 조금 시간이 지나서 저장을하면 다시 로그인으로 넘어가 자주 내용이 사라집니다. 왜그런지요?',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(120,'mobqna',-120,1,0,NULL,120,0,NULL,1,1,NULL,NULL,NULL,1,0,'최보아스',0,'49.167.144.244',1515512045,NULL,7,NULL,NULL,NULL,'맥체인 마태복음 23장 오류',0,'최보아스','boazchoi','magiri@naver.com',NULL,NULL,NULL,'',0,NULL,'해당장에 오류가 있나봅니다\r\n다음장으로 안 넘어 갑니다\r\n조치 부탁드려요.\r\n섬김에 감사 드립니다^^',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(121,'mobqna',-121,1,0,NULL,121,0,NULL,1,1,NULL,NULL,NULL,1,0,'헌그리',0,'223.57.151.223',1521380795,NULL,11,NULL,NULL,NULL,'공유 양식 게시판',0,'헌그리','khk1008','khk1008@naver.com',NULL,NULL,NULL,'',0,NULL,'제목과 내용이 없는 것도 공유양식 게시판에 올려져 있는 것 같습니다. 삭제하는게 낫지 않을까요?? 아니면 내용이 일정량 없으면 글이 못 올라가게 하는 방법이 있으면 어떨지요;;;??',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL),(122,'mobqna',-122,1,0,NULL,122,0,NULL,1,1,NULL,NULL,NULL,1,0,'IsaacPyeon',0,'14.42.83.35',1528506858,NULL,12,NULL,NULL,NULL,'맥체인 성경읽기에 \"성경필사\" 기능이 포함되었으면 좋겠습니다.',0,'IsaacPyeon','isaacpyeon','powerpyeon@gmail.com',NULL,NULL,NULL,'',0,NULL,'안녕하세요. 저는 화랑센터 편이삭 목자입니다.\r\n\r\n좋은 앱을 개발해 주셔서 잘 사용하고 있어 깊이 감사드립니다.\r\n\r\n다름이 아니오라, 맥체인 성경읽기를 꾸준히 하고자 노력하고 있는 중인데, GODPIA에 있는 성경 필사 기능이 포함되면\r\n말씀을 좀 더 마음에 새길 수 있을 것 같아 제안을 드립니다. 물론 눈으로 읽고, 입으로 소리내어 읽어도 좋습니다. 또 본인이 손으로 필사해도 좋지만, 하루에 4장 이상을 손으로 쓰는 것도 시간이 너무 걸리고 해서, 맥체인 성경읽기 기능에 \"성경 필사\" 기능이 포함되면 좋을 것 같습니다. ',NULL,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,0,NULL,NULL,0,NULL,NULL,NULL,'none',NULL,NULL);
